import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { id } = useParams(); // ✅ get doctor id from URL
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // ✅ Fetch doctor details from API
  useEffect(() => {
    const fetchDoctor = async () => {
      try {
        const response = await fetch(
          `http://127.0.0.1:8000/doctor-details/${id}/`,
          {
            headers: {
              "Authorization": `Token ${localStorage.getItem("token")}`,
            },
          }
        );

        const data = await response.json();

        if (response.ok) {
          setDoctor(data.doctor);
        } else {
          console.error(data);
        }
      } catch (error) {
        console.error(error);
      }
    };

    fetchDoctor();
  }, [id]);

  // ✅ Handle booking redirect
  const handleBooking = () => {
    if (!date || !time) {
      alert("Please select date and time");
      return;
    }

    navigate("/book", {
      state: {
        doctor,
        date,
        time,
      },
    });
  };

  // ✅ Prevent crash before data loads
  if (!doctor) return <h2 style={{ textAlign: "center" }}>Loading...</h2>;

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>
        <div style={styles.card}>
          
          {/* Left */}
          <div style={styles.left}>
            <img
              src={
                doctor.image
                  ? `http://127.0.0.1:8000/media/${doctor.image}`
                  : "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt="doctor"
              style={styles.image}
            />
          </div>

          {/* Right */}
          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><strong>Specialization:</strong> {doctor.field}</p>
            <p><strong>Experience:</strong> {doctor.experience} Years</p>
            <p><strong>Qualification:</strong> {doctor.qualification}</p>

            <p style={styles.about}>
              <strong>About:</strong> Experienced doctor with strong patient care.
            </p>

            {/* Booking Section */}
            <div style={styles.bookingSection}>

              <label>Select Date:</label>
              <input
                type="date"
                style={styles.input}
                value={date}
                onChange={(e) => setDate(e.target.value)}
              />

              <label>Select Time:</label>
              <select
                style={styles.input}
                value={time}
                onChange={(e) => setTime(e.target.value)}
              >
                <option value="">Select time</option>
                <option>10:00 AM</option>
                <option>11:00 AM</option>
                <option>02:00 PM</option>
                <option>04:00 PM</option>
              </select>

              <button style={styles.button} onClick={handleBooking}>
                Book Appointment
              </button>

            </div>
          </div>

        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;
